import org.apache.commons.text.StringEscapeUtils;

public class SecureXSSDemo {

    public static void main(String[] args) {
        // Simulating user input, which could come from a form submission or other user input source
        String userInput = "<script>alert('XSS attack!')</script>";

        // Sanitize user input to prevent XSS attacks
        String sanitizedInput = StringEscapeUtils.escapeHtml4(userInput);

        // Properly handling user input with sanitized output
        String output = "Hello, " + sanitizedInput + "!";

        System.out.println(output);
    }
}

